async getUserJournals(token: string, userId: string, cursor: string | null, limit = 10): Promise<CursorPage<JournalItem>> {
  const params = new URLSearchParams();
  params.set('limit', String(limit));
  params.set('userId', userId);
  if (cursor) params.set('before', cursor);
  return apiRequest<CursorPage<JournalItem>>(`/userJournals?${params.toString()}`, {
    method: 'GET',
    headers: {Authorization: `Bearer ${token}`},
  });
},

async deleteJournal(token: string, journalId: string): Promise<{message?: string}> {
  return apiRequest<{message?: string}>(`/deleteJournal/${encodeURIComponent(journalId)}`, {
    method: 'DELETE',
    headers: {Authorization: `Bearer ${token}`},
  });
},

async updatePrivacy(token: string, payload: {journalId: string; privacy: string}): Promise<{message?: string}> {
  const formData = new FormData();
  formData.append('journalId', payload.journalId);
  formData.append('privacy', payload.privacy);
  return apiRequest<{message?: string}>('/updatePrivacy', {
    method: 'POST',
    headers: {Authorization: `Bearer ${token}`},
    body: formData,
    retries: 0,
  });
},

