162→export async function apiRequest<T>(path: string, init: ApiRequestInit = {}): Promise<T> {
163→  const method = (init.method ?? 'GET').toUpperCase();
164→  const timeoutMs = init.timeoutMs ?? DEFAULT_TIMEOUT_MS;
165→  const retries = Math.max(0, Math.floor(init.retries ?? DEFAULT_RETRIES));
166→  const callerSignal = init.signal;
167→  const requestInit: RequestInit = { ...init };
168→  delete (requestInit as ApiRequestInit).timeoutMs;
169→  delete (requestInit as ApiRequestInit).retries;
170→  requestInit.method = method;
171→
172→  const headers = new Headers(requestInit.headers ?? {});
173→  if (!headers.has('Accept')) {
174→    headers.set('Accept', 'application/json');
175→  }
176→  requestInit.headers = headers;
177→
178→  const maxAttempts = shouldRetryMethod(method) ? retries + 1 : 1;
179→
180→  for (let attempt = 0; attempt < maxAttempts; attempt += 1) {
181→    const controller = new AbortController();
182→    let timeoutId: ReturnType<typeof setTimeout> | null = null;
183→    let didTimeout = false;
184→    let callerAbortListener: (() => void) | null = null;
185→
186→    if (callerSignal) {
187→      if (callerSignal.aborted) {
188→        controller.abort();
189→      } else {
190→        callerAbortListener = () => controller.abort();
191→        callerSignal.addEventListener('abort', callerAbortListener, { once: true });
192→      }
193→    }
194→
195→    if (timeoutMs > 0) {
196→      timeoutId = setTimeout(() => {
197→        didTimeout = true;
198→        controller.abort();
199→      }, timeoutMs);
200→    }
201→
202→    try {
203→      const response = await fetch(buildUrl(path), {
204→        ...requestInit,
205→        signal: controller.signal,
206→      });
207→
208→      const body = await parseBody(response);
209→
210→      if (!response.ok) {
211→        if (attempt < maxAttempts - 1 && shouldRetryStatus(response.status)) {
212→          const retryAfterMs = parseRetryAfterMs(response.headers.get('retry-after'));
213→          await wait(backoffDelay(attempt, retryAfterMs));
214→          continue;
215→        }
216→
217→        const message = extractErrorMessage(response.status, response.statusText ?? '', body);
218→
219→        throw new ApiError(message, response.status, body);
220→      }
221→
222→      return body as T;
223→    } catch (error) {
224→      const normalizedError = normalizeError(error, timeoutMs, didTimeout, callerSignal);
225→
226→      if (attempt < maxAttempts - 1 && shouldRetryError(normalizedError)) {
227→        await wait(backoffDelay(attempt));
228→        continue;
229→      }
230→
231→      throw normalizedError;
232→    } finally {
