    params.set('userId', userId);
    params.set('limit', String(limit));
    if (cursor) params.set('cursor', cursor);
    return apiRequest('/visitedProfileMedia?' + params.toString(), {
      method: 'GET',
      headers: {Authorization: `Bearer ${token}`},
